import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  // --- ESTADOS ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');

  // Nuevos estados para la lógica real
  const [userRole, setUserRole] = useState(''); // Para distinguir Admin de Vendedor
  const [view, setView] = useState('dashboard'); // Para cambiar entre 'dashboard' y 'gestion'
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);

  // --- FUNCIONES DE CARGA (API) ---

  // Obtener estadísticas de la base de datos
  const cargarDatos = async () => {
    try {
      const resStats = await axios.get('http://localhost:5000/api/stats');
      setStats(resStats.data);

      const resProds = await axios.get('http://localhost:5000/api/productos');
      setProductos(resProds.data);
    } catch (error) {
      console.error("Error al cargar datos de SQL", error);
    }
  };

  // Cargar datos automáticamente cuando se loguea
  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
    }
  }, [isLoggedIn]);

  // --- MANEJADORES DE EVENTOS ---

  const handleLogin = async () => {
    try {
      const respuesta = await axios.post('http://localhost:5000/api/login', {
        usuario: usuario,
        clave: password
      });

      if (respuesta.data.success) {
        setIsLoggedIn(true);
        setUserRole(respuesta.data.rol); // Guardamos el rol que viene de SQL
      }
    } catch (error) {
      alert("Error: " + (error.response?.data?.message || "No se pudo conectar"));
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setView('dashboard');
  };

  // --- RENDERIZADO CONDICIONAL ---

  // 1. VISTA DE LOGIN
  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>Iniciar Sesión</h2>
          <div className="form-group">
            <label>Usuario:</label>
            <input 
              type="text" 
              placeholder="eduardo" 
              value={usuario}
              onChange={(e) => setUsuario(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Contraseña:</label>
            <input 
              type="password" 
              placeholder="••••••••••••" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          <button className="btn-entrar" onClick={handleLogin}>Entrar</button>
          <button className="btn-registrar">Registrarse</button>
        </div>
      </div>
    );
  }

  // 2. VISTA PRINCIPAL (DASHBOARD Y GESTIÓN)
  return (
    <div>
      <header className="header">
        <h1 style={{ margin: 0, fontSize: '24px' }}>Mi Tiendita - {view === 'dashboard' ? 'Dashboard' : 'Gestión'}</h1>
        <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
          <span>Hola, <strong>{usuario}</strong> ({userRole})</span>
          <button className="btn-cerrar" onClick={handleLogout}>Cerrar Sesión</button>
        </div>
      </header>

      <nav className="nav-bar">
        <span className="nav-link" onClick={() => setView('dashboard')}>Inicio / Dashboard</span>

        {/* Solo el Admin puede ver la opción de Gestionar */}
        {userRole === 'admin' && (
          <span className="nav-link" onClick={() => setView('gestion')}>Gestionar Productos</span>
        )}

        <span className="nav-link">Registrar Movimientos</span>
      </nav>

      <main style={{ padding: '20px' }}>
        {view === 'dashboard' ? (
          // CONTENIDO DEL DASHBOARD
          <div className="dashboard-grid">
            <div className="card">
              <h3>Productos con Bajo Stock</h3>
              <div className="card-content">
                {stats.bajo_stock > 0 
                  ? `¡Atención! Tienes ${stats.bajo_stock} productos agotándose.` 
                  : "Todo en orden con el inventario."}
              </div>
            </div>

            <div className="card">
              <h3>Productos Próximos a Caducar</h3>
              <div className="card-content">
                {/* Aquí podríamos filtrar los productos de la lista 'productos' */}
                Filtro de caducidad activo.
              </div>
            </div>

            <div className="card">
              <h3>Resumen Diario</h3>
              <div className="card-content">Ventas de hoy: $0.00</div>
            </div>

            <div className="card">
              <h3>Estadísticas Rápidas</h3>
              <div className="card-content">
                <p>Total de Productos: <strong>{stats.total_productos}</strong></p>
                <p>Valor del Inventario: <strong>${stats.valor_inventario}</strong></p>
              </div>
            </div>
          </div>
        ) : (
          // CONTENIDO DE GESTIÓN DE PRODUCTOS (Solo Admin)
          <div className="card" style={{ width: '100%', boxSizing: 'border-box' }}>
            <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '20px'}}>
               <h3>Listado de Inventario</h3>
               <button className="btn-entrar" style={{width: 'auto', padding: '10px 20px'}}>+ Agregar Producto</button>
            </div>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '2px solid #eee', textAlign: 'left' }}>
                  <th>Nombre</th>
                  <th>Categoría</th>
                  <th>Stock</th>
                  <th>Precio Venta</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {productos.map(p => (
                  <tr key={p.id} style={{ borderBottom: '1px solid #eee' }}>
                    <td style={{ padding: '10px 0' }}>{p.nombre}</td>
                    <td>{p.categoria}</td>
                    <td>{p.stock}</td>
                    <td>${p.precio_venta}</td>
                    <td>
                      <button style={{marginRight: '5px'}}>Editar</button>
                      <button style={{color: 'red'}}>Eliminar</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
